@cython.boundscheck(False)
@cython.wraparound(False)
cdef void normalize_columns(double[:, ::1] D):
    cdef int m = D.shape[0]
    cdef int n = D.shape[1]

    cdef int row, col
    cdef double acc

    for col in range(n):
        acc = 0.
        for row in range(m):
            acc += D[row, col]**2

        acc = sqrt(acc)

        for row in range(m):
            D[row, col] /= acc


@cython.boundscheck(False)
@cython.wraparound(False)
def construct_dictionary(double[:, ::1] D):
    cdef int m = D.shape[0]
    cdef int n = D.shape[1]

    cdef int row, col

    for row in range(m):
        D[row, 0] = n**(-.5)

    for col in range(1, n):
        for row in range(m):
            D[row, col] = (2. / n)**(.5) * cos(M_PI / n * (row + .5) * col)

    normalize_columns(D)


@cython.boundscheck(False)
@cython.wraparound(False)
cdef void mp(double[:] x,
             double[:, ::1] D,
             double[:] r_buf,
             double[:] s_buf,
             int iter_max,
             double global_eps):

    cdef int m = D.shape[0]
    cdef int n = D.shape[1]

    cdef int i, row, col
    cdef double acc

    cdef int w_argmax
    cdef double w_max

    for col in range(n):
        s_buf[col] = 0.

    if iter_max < 0:
        iter_max = n

    r_buf[:] = x
    for i in range(iter_max):
        w_max = 0.
        w_argmax = 0

        for col in range(n):
            acc = 0.
            for row in range(m):
                acc += D[row, col] * r_buf[row]

            if abs(acc) > abs(w_max):
                w_max = acc
                w_argmax = col

        s_buf[w_argmax] = w_max

        acc = 0.
        for row in range(m):
            r_buf[row] -= w_max * D[row, w_argmax]
            acc += r_buf[row]**2

        if sqrt(acc) < global_eps:
            break


